import sys
from typing import List

def solve(nums: List[int], queries: List[List[int]]) -> List[int]:
    # Precompute popcount-depth for numbers up to 1e15
    # Since the maximum popcount-depth is small (<=5 for numbers up to 1e15), we can memoize
    depth_memo = {}
    depth_memo[0] = 0  # edge case, though x is positive in problem statement
    depth_memo[1] = 0

    def get_popcount(x: int) -> int:
        return bin(x).count('1')

    def get_depth(x: int) -> int:
        if x in depth_memo:
            return depth_memo[x]
        pop = get_popcount(x)
        depth = 1 + get_depth(pop)
        depth_memo[x] = depth
        return depth

    # Precompute depths for all nums initially
    depths = [0] * len(nums)
    for i in range(len(nums)):
        depths[i] = get_depth(nums[i])

    # Process queries
    answer = []
    for query in queries:
        if query[0] == 1:
            _, l, r, k = query
            count = 0
            for i in range(l, r + 1):
                if depths[i] == k:
                    count += 1
            answer.append(count)
        elif query[0] == 2:
            _, idx, val = query
            nums[idx] = val
            depths[idx] = get_depth(val)

    return answer
